   116→// Represents the overflow mark stack used by concurrent marking.
   117→//
   118→// Stores oops in a huge buffer in virtual memory that is always fully committed.
   119→// Resizing may only happen during a STW pause when the stack is empty.
   120→//
   121→// Memory is allocated on a "chunk" basis, i.e. a set of oops. For this, the mark
   122→// stack memory is split into evenly sized chunks of oops. Users can only
   123→// add or remove entries on that basis.
   124→// Chunks are filled in increasing address order. Not completely filled chunks
   125→// have a null element as a terminating element.
   126→//
   127→// Every chunk has a header containing a single pointer element used for memory
   128→// management. This wastes some space, but is negligible (< .1% with current sizing).
   129→//
   130→// Memory management is done using a mix of tracking a high water-mark indicating
   131→// that all chunks at a lower address are valid chunks, and a singly linked free
   132→// list connecting all empty chunks.
   133→class G1CMMarkStack {
   134→public:
   135→  // Number of TaskQueueEntries that can fit in a single chunk.
   136→  static const size_t EntriesPerChunk = 1024 - 1 /* One reference for the next pointer */;
   137→private:
   138→  struct TaskQueueEntryChunk {
   139→    TaskQueueEntryChunk* next;
   140→    G1TaskQueueEntry data[EntriesPerChunk];
   141→  };
   142→
   143→  class ChunkAllocator {
   144→    // The chunk allocator relies on a growable array data structure that allows resizing without the
   145→    // need to copy existing items. The basic approach involves organizing the array into chunks,
   146→    // essentially creating an "array of arrays"; referred to as buckets in this implementation. To
   147→    // facilitate efficient indexing, the size of the first bucket is set to a power of 2. This choice
   148→    // allows for quick conversion of an array index into a bucket index and the corresponding offset
   149→    // within the bucket. Additionally, each new bucket added to the growable array doubles the capacity of
   150→    // the growable array.
   151→    //
   152→    // Illustration of the growable array data structure.
   153→    //
   154→    //        +----+        +----+----+
   155→    //        |    |------->|    |    |
   156→    //        |    |        +----+----+
   157→    //        +----+        +----+----+
   158→    //        |    |------->|    |    |
   159→    //        |    |        +----+----+
   160→    //        +----+        +-----+-----+-----+-----+
   161→    //        |    |------->|     |     |     |     |
   162→    //        |    |        +-----+-----+-----+-----+
   163→    //        +----+        +-----+-----+-----+-----+-----+-----+-----+----+
   164→    //        |    |------->|     |     |     |     |     |     |     |    |
   165→    //        |    |        +-----+-----+-----+-----+-----+-----+-----+----+
   166→    //        +----+
   167→    //
   168→    size_t _min_capacity;
   169→    size_t _max_capacity;
   170→    size_t _capacity;
   171→    size_t _num_buckets;
   172→    bool _should_grow;
   173→    TaskQueueEntryChunk* volatile* _buckets;
   174→    char _pad0[DEFAULT_PADDING_SIZE];
   175→    volatile size_t _size;
   176→    char _pad4[DEFAULT_PADDING_SIZE - sizeof(size_t)];
   177→
   178→    size_t bucket_size(size_t bucket) {
   179→      return (bucket == 0) ?
   180→              _min_capacity :
   181→              _min_capacity * ( 1ULL << (bucket - 1));
   182→    }
   183→
   184→    static unsigned int find_highest_bit(uintptr_t mask) {
   185→      return count_leading_zeros(mask) ^ (BitsPerWord - 1U);
   186→    }
   187→
   188→    size_t get_bucket(size_t array_idx) {
   189→      if (array_idx < _min_capacity) {
   190→        return 0;
   191→      }
   192→
   193→      return find_highest_bit(array_idx) - find_highest_bit(_min_capacity) + 1;
   194→    }
   195→
   196→    size_t get_bucket_index(size_t array_idx) {
   197→      if (array_idx < _min_capacity) {
   198→        return array_idx;
   199→      }
   200→      return array_idx - (1ULL << find_highest_bit(array_idx));
   201→    }
   202→
   203→    bool reserve(size_t new_capacity);
   204→
   205→  public:
   206→    ChunkAllocator();
   207→
   208→    ~ChunkAllocator();
   209→
   210→    bool initialize(size_t initial_capacity, size_t max_capacity);
   211→
   212→    void reset() {
   213→      _size = 0;
   214→      _should_grow = false;
   215→    }
   216→
   217→    // During G1CMConcurrentMarkingTask or finalize_marking phases, we prefer to restart the marking when
   218→    // the G1CMMarkStack overflows. Attempts to expand the G1CMMarkStack should be followed with a restart
   219→    // of the marking. On failure to allocate a new chuck, the caller just returns and forces a restart.
   220→    // This approach offers better memory utilization for the G1CMMarkStack, as each iteration of the
   221→    // marking potentially involves traversing fewer unmarked nodes in the graph.
   222→
   223→    // However, during the reference processing phase, instead of restarting the marking process, the
   224→    // G1CMMarkStack is expanded upon failure to allocate a new chunk. The decision between these two
   225→    // modes of expansion is determined by the _should_grow parameter.
   226→    void set_should_grow() {
   227→      _should_grow = true;
   228→    }
   229→
   230→    size_t capacity() const { return _capacity; }
   231→
   232→    // Expand the mark stack doubling its size.
   233→    bool try_expand();
   234→    bool try_expand_to(size_t desired_capacity);
   235→
   236→    TaskQueueEntryChunk* allocate_new_chunk();
   237→  };
   238→
   239→  ChunkAllocator _chunk_allocator;
   240→
   241→  char _pad0[DEFAULT_PADDING_SIZE];
   242→  TaskQueueEntryChunk* volatile _free_list;  // Linked list of free chunks that can be allocated by users.
   243→  char _pad1[DEFAULT_PADDING_SIZE - sizeof(TaskQueueEntryChunk*)];
   244→  TaskQueueEntryChunk* volatile _chunk_list; // List of chunks currently containing data.
   245→  volatile size_t _chunks_in_chunk_list;
   246→  char _pad2[DEFAULT_PADDING_SIZE - sizeof(TaskQueueEntryChunk*) - sizeof(size_t)];
   247→
   248→  // Atomically add the given chunk to the list.
   249→  void add_chunk_to_list(TaskQueueEntryChunk* volatile* list, TaskQueueEntryChunk* elem);
   250→  // Atomically remove and return a chunk from the given list. Returns null if the
   251→  // list is empty.
   252→  TaskQueueEntryChunk* remove_chunk_from_list(TaskQueueEntryChunk* volatile* list);
   253→
   254→  void add_chunk_to_chunk_list(TaskQueueEntryChunk* elem);
   255→  void add_chunk_to_free_list(TaskQueueEntryChunk* elem);
   256→
   257→  TaskQueueEntryChunk* remove_chunk_from_chunk_list();
   258→  TaskQueueEntryChunk* remove_chunk_from_free_list();
   259→
   260→ public:
   261→  G1CMMarkStack();
   262→  ~G1CMMarkStack() = default;
   263→
   264→  // Alignment and minimum capacity of this mark stack in number of oops.
   265→  static size_t capacity_alignment();
   266→
   267→  // Allocate and initialize the mark stack.
   268→  bool initialize();
   269→
   270→  // Pushes the given buffer containing at most EntriesPerChunk elements on the mark
   271→  // stack. If less than EntriesPerChunk elements are to be pushed, the array must
   272→  // be terminated with a null.
   273→  // Returns whether the buffer contents were successfully pushed to the global mark
   274→  // stack.
   275→  bool par_push_chunk(G1TaskQueueEntry* buffer);
   276→
   277→  // Pops a chunk from this mark stack, copying them into the given buffer. This
   278→  // chunk may contain up to EntriesPerChunk elements. If there are less, the last
   279→  // element in the array is a null pointer.
   280→  bool par_pop_chunk(G1TaskQueueEntry* buffer);
   281→
   282→  // Return whether the chunk list is empty. Racy due to unsynchronized access to
   283→  // _chunk_list.
   284→  bool is_empty() const { return _chunk_list == nullptr; }
   285→
   286→  size_t capacity() const  { return _chunk_allocator.capacity(); }
   287→
   288→  void set_should_grow() {
   289→    _chunk_allocator.set_should_grow();
   290→  }
   291→
   292→  // Expand the stack, typically in response to an overflow condition
   293→  void expand();
   294→
   295→  // Return the approximate number of oops on this mark stack. Racy due to
   296→  // unsynchronized access to _chunks_in_chunk_list.
   297→  size_t size() const { return _chunks_in_chunk_list * EntriesPerChunk; }
   298→
   299→  void set_empty();
   300→
   301→  // Apply Fn to every oop on the mark stack. The mark stack must not
   302→  // be modified while iterating.
   303→  template<typename Fn> void iterate(Fn fn) const PRODUCT_RETURN;
   304→};
